-- DigiDocs Mgt 开发环境种子数据
-- 执行前提：已通过 Go 端自动迁移初始化 schema（001_initial_schema.sql）
-- 用法：psql -h localhost -p 15432 -U postgres -d digidocs_mgt -f backend-go/sql/seed.sql

BEGIN;

-- ========== 用户 ==========
-- 所有用户密码均为 admin123
ON CONFLICT (id) DO UPDATE
SET username = EXCLUDED.username,
    display_name = EXCLUDED.display_name,
    role = EXCLUDED.role,
    email = COALESCE(users.email, EXCLUDED.email),
    phone = COALESCE(users.phone, EXCLUDED.phone),
    wechat = COALESCE(users.wechat, EXCLUDED.wechat),
    status = EXCLUDED.status,
    updated_at = NOW();

-- ========== 团队空间 ==========
ON CONFLICT (name) DO NOTHING;

-- ========== 项目 ==========
ON CONFLICT ON CONSTRAINT uq_projects_team_space_code DO NOTHING;

-- ========== 项目成员 ==========
ON CONFLICT ON CONSTRAINT uq_project_members_project_user DO UPDATE
SET project_role = EXCLUDED.project_role,
    updated_at = NOW();

-- ========== 目录 ==========
ON CONFLICT ON CONSTRAINT uq_folders_project_path DO NOTHING;

-- ========== 文档 ==========
